const controls = document.querySelectorAll('input, button');
controls.forEach(ctl => {
  ctl.disabled = true;
});

for (Component control : frame.getComponents()) {
  if (control instanceof JButton) {
    ((JButton) control).setEnabled(false);
  }
}

CREATE TABLE form_controls (
  control_id INT,
  control_name VARCHAR(50),
  enabled BIT DEFAULT 1
);
